/**
 * components/Layout.jsx — Main layout: sidebar + top header + content area.
 */
import { useLocation } from 'react-router-dom';
import Sidebar from './Sidebar';

const PAGE_META = {
  '/':          { title: 'Dashboard',         icon: '📊', sub: 'Overview & KPIs' },
  '/milk':      { title: 'Milk Entry',        icon: '🥛', sub: 'Daily collection records' },
  '/cattle':    { title: 'Cattle Health',     icon: '🐄', sub: 'Health & vaccination tracking' },
  '/inventory': { title: 'Inventory',         icon: '📦', sub: 'Stock & supply management' },
  '/sales':     { title: 'Sales',             icon: '💰', sub: 'Milk & Ghee sales records' },
  '/employees': { title: 'Employee Roster',   icon: '👥', sub: 'Staff & attendance' },
  '/reports':   { title: 'Financial Reports', icon: '📈', sub: 'Revenue & expense reports' },
};

function TopHeader() {
  const location = useLocation();
  const meta = PAGE_META[location.pathname] || { title: 'Akshaya Farm Dairy', icon: '🥛', sub: '' };
  const today = new Date().toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });

  return (
    <header className="sticky top-0 z-10 bg-white border-b border-gray-100 shadow-sm">
      <div className="flex items-center justify-between px-6 py-3.5">
        {/* Page title */}
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl bg-green-50 border border-green-100 flex items-center justify-center text-xl">
            {meta.icon}
          </div>
          <div>
            <h1 className="text-base font-bold text-gray-900 leading-tight">{meta.title}</h1>
            {meta.sub && <p className="text-xs text-gray-400 mt-0.5">{meta.sub}</p>}
          </div>
        </div>

        {/* Right: date + indicator */}
        <div className="flex items-center gap-4">
          <div className="text-right hidden sm:block">
            <p className="text-xs font-medium text-gray-700">{today}</p>
            <p className="text-[10px] text-gray-400 mt-0.5">Akshaya Farm Dairy</p>
          </div>
          {/* Online indicator */}
          <div className="flex items-center gap-1.5 bg-green-50 border border-green-100 px-3 py-1.5 rounded-full">
            <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse inline-block" />
            <span className="text-xs text-green-700 font-medium">Live</span>
          </div>
        </div>
      </div>
    </header>
  );
}

export default function Layout({ children }) {
  return (
    <div className="flex min-h-screen" style={{ background: '#f8faf9' }}>
      <Sidebar />
      <div className="flex-1 ml-64 flex flex-col min-h-screen">
        <TopHeader />
        <main className="flex-1 p-6 overflow-auto">
          {children}
        </main>
        <footer className="px-6 py-3 border-t border-gray-100 bg-white">
          <p className="text-xs text-gray-400 text-center">
            © 2026 Akshaya Farm Dairy · Management System
          </p>
        </footer>
      </div>
    </div>
  );
}
